    for (auto& entry : freq) {
        groups[entry.second].push_back(entry.first);
    }

    int max_size = 0;
    int max_k = 0;
    for (auto& entry : groups) {
        int k = entry.first;
        int current_size = entry.second.size();
        if (current_size > max_size) {
            max_size = current_size;
            max_k = k;
        } else if (current_size == max_size && k > max_k) {
            max_k = k;
        }
    }

    string result;
    for (char c : groups[max_k]) {
        result += c;
    }

    return result;
}
