using namespace std;

string solve(string s) {
    unordered_map<char, int> freq;
    for (char c : s) {
        freq[c]++;
    }

    unordered_map<int, vector<char>> freqGroups;
    for (auto& pair : freq) {
        freqGroups[pair.second].push_back(pair.first);
    }

    int maxSize = 0;
    int maxK = 0;
    for (auto& group : freqGroups) {
        int currentSize = group.second.size();
        int currentK = group.first;
        if (currentSize > maxSize) {
            maxSize = currentSize;
            maxK = currentK;
        } else if (currentSize == maxSize && currentK > maxK) {
            maxK = currentK;
        }
    }

    vector<char> resultChars = freqGroups[maxK];
    sort(resultChars.begin(), resultChars.end());
    string result(resultChars.begin(), resultChars.end());

    return result;
}
